module alu_32bit (
  input [31:0] operand_a,
  input [31:0] operand_b,
  input [2:0] opcode,
  output [31:0] result
);
  always @(*) begin
    case(opcode)
      3'b000: result = operand_a + operand_b;
      3'b001: result = operand_a - operand_b;
      3'b010: result = operand_a & operand_b;
      default: result = 32'h0;
    endcase
  end
endmodule

module datapath (
  input [31:0] x,
  input [31:0] y,
  input [2:0] op,
  output [31:0] out
);
  alu_32bit alu_inst (
    .operand_a(x),
    .operand_b(y),
    .opcode(op),
    .result(out),
    .extra_port(1'b0)  // BUG: 'extra_port' does not exist in alu_32bit module
  );
endmodule

